import { HEAVENLY_STEMS, getStemWeight } from '../constants/heavenly-stems.js';
import { EARTHLY_BRANCHES, getBranchWeight } from '../constants/earthly-branches.js';
import { FIVE_ELEMENTS } from '../constants/five-elements.js';

/**
 * Lấy ra chuỗi mô tả toàn bộ Can, Chi và Mệnh dựa vào số năm (Ví dụ: 2024)
 * Theo quy ước: Năm 4 (sau CN) là năm Giáp Tý (Can index 0, Chi index 0)
 */
export function getYearDetails(year: number) {
  // Tính index của Can và Chi dựa trên mốc năm gốc
  // Năm 1984, 2044 là Giáp Tý -> Offset để tính toán dễ nhất là lấy (year - 4) % hệ cơ số
  const stemIndex = (year - 4) % 10;
  const branchIndex = (year - 4) % 12;

  // Công thức vàng tính Ngũ Hành
  const stemWeight = getStemWeight(stemIndex);
  const branchWeight = getBranchWeight(branchIndex);
  
  let elementValue = stemWeight + branchWeight;
  if (elementValue > 5) {
    elementValue -= 5;
  }

  // Value ra từ 1-5, nên trừ 1 để lấy index của mảng FIVE_ELEMENTS (0-4)
  const elementIndex = elementValue - 1;

  return {
    can: HEAVENLY_STEMS[stemIndex],
    chi: EARTHLY_BRANCHES[branchIndex],
    menh: FIVE_ELEMENTS[elementIndex],
    fullString: `${HEAVENLY_STEMS[stemIndex]} ${EARTHLY_BRANCHES[branchIndex]} - Mệnh ${FIVE_ELEMENTS[elementIndex]}`
  };
}

// ============================================================
// Can Chi cho Ngày, Tháng, Giờ
// ============================================================

/**
 * Tính Can Chi ngày từ Julian Day Number.
 *
 * @param jd - Julian Day Number
 * @returns Chuỗi Can Chi (ví dụ: "Giáp Tý")
 */
export function getDayCanChi(jd: number): string {
  const stemIndex = (jd + 9) % 10;
  const branchIndex = (jd + 1) % 12;
  return `${HEAVENLY_STEMS[stemIndex]} ${EARTHLY_BRANCHES[branchIndex]}`;
}

/**
 * Tính Can Chi tháng từ tháng và năm âm lịch.
 * Can tháng phụ thuộc vào Can của năm (quy tắc Ngũ Hổ Độn):
 *   - Năm Giáp/Kỷ  → Tháng Giêng bắt đầu bằng Bính (index 2)
 *   - Năm Ất/Canh  → Tháng Giêng bắt đầu bằng Mậu (index 4)
 *   - Năm Bính/Tân → Tháng Giêng bắt đầu bằng Canh (index 6)
 *   - Năm Đinh/Nhâm → Tháng Giêng bắt đầu bằng Nhâm (index 8)
 *   - Năm Mậu/Quý  → Tháng Giêng bắt đầu bằng Giáp (index 0)
 *
 * @param lunarMonth - Tháng âm lịch (1-12)
 * @param lunarYear - Năm âm lịch
 */
export function getMonthCanChi(lunarMonth: number, lunarYear: number): string {
  const yearStemIndex = (lunarYear + 6) % 10;
  const monthStemOffset = (yearStemIndex % 5) * 2 + 2;
  const monthStemIndex = (monthStemOffset + lunarMonth - 1) % 10;
  const monthBranchIndex = (lunarMonth + 1) % 12;
  return `${HEAVENLY_STEMS[monthStemIndex]} ${EARTHLY_BRANCHES[monthBranchIndex]}`;
}

/**
 * Tính Can Chi giờ từ giờ (0-23) và Julian Day Number của ngày.
 *
 * 12 canh giờ (mỗi canh = 2 tiếng):
 *   Tý: 23h-01h, Sửu: 01h-03h, Dần: 03h-05h, ...
 *
 * Can giờ Tý phụ thuộc Can ngày (quy tắc Ngũ Thử Độn):
 *   - Ngày Giáp/Kỷ → Giờ Tý bắt đầu bằng Giáp
 *   - Ngày Ất/Canh → Giờ Tý bắt đầu bằng Bính
 *   - Ngày Bính/Tân → Giờ Tý bắt đầu bằng Mậu
 *   - Ngày Đinh/Nhâm → Giờ Tý bắt đầu bằng Canh
 *   - Ngày Mậu/Quý → Giờ Tý bắt đầu bằng Nhâm
 *
 * @param hour - Giờ (0-23)
 * @param dayJd - Julian Day Number của ngày
 */
export function getHourCanChi(hour: number, dayJd: number): string {
  // Tính Địa Chi của giờ: Tý từ 23h, mỗi canh 2 tiếng
  const hourBranchIndex = Math.floor((hour + 1) / 2) % 12;

  // Tính Thiên Can của giờ dựa vào Can ngày
  const dayStemIndex = (dayJd + 9) % 10;
  const hourStemOffset = (dayStemIndex % 5) * 2;
  const hourStemIndex = (hourStemOffset + hourBranchIndex) % 10;

  return `${HEAVENLY_STEMS[hourStemIndex]} ${EARTHLY_BRANCHES[hourBranchIndex]}`;
}

// ============================================================
// Giờ Hoàng Đạo
// ============================================================

/**
 * Bảng giờ Hoàng Đạo theo Chi của ngày.
 * Mỗi hàng tương ứng với 2 Chi (Tý-Ngọ, Sửu-Mùi, ...) → 6 nhóm.
 * Giá trị là index các Địa Chi tốt (6 giờ tốt trong 12 canh).
 */
const AUSPICIOUS_HOURS_TABLE: readonly (readonly number[])[] = [
  [0, 1, 3, 6, 7, 9],   // Ngày Tý (0) / Ngọ (6)
  [2, 3, 5, 8, 9, 11],  // Ngày Sửu (1) / Mùi (7)
  [0, 1, 4, 5, 7, 10],  // Ngày Dần (2) / Thân (8)
  [1, 2, 4, 7, 8, 10],  // Ngày Mão (3) / Dậu (9)
  [0, 3, 4, 6, 9, 10],  // Ngày Thìn (4) / Tuất (10)
  [2, 5, 6, 8, 11, 0],  // Ngày Tỵ (5) / Hợi (11)
] as const;

/**
 * Lấy danh sách 6 giờ Hoàng Đạo trong ngày.
 * Giờ Hoàng Đạo phụ thuộc vào Địa Chi của ngày.
 *
 * @param dayJd - Julian Day Number của ngày
 * @returns Mảng 6 chuỗi tên Địa Chi (ví dụ: ["Tý", "Sửu", "Mão", "Ngọ", "Mùi", "Dậu"])
 */
export function getAuspiciousHours(dayJd: number): string[] {
  const branchIndex = (dayJd + 1) % 12;
  // Nhóm theo 2 Chi (Tý-Ngọ, Sửu-Mùi, ...)
  const groupIndex = branchIndex % 6;
  const hourIndices = AUSPICIOUS_HOURS_TABLE[groupIndex];
  return hourIndices.map((i) => EARTHLY_BRANCHES[i] as string);
}